export function getWebsitesByCategory(category: string): Website[] {
  return websites.filter(w => w.category === category);
}

export function getTrendingWebsites(): Website[] {
  return websites.filter(w => w.trending);
}

export function getRecentlyAdded(): Website[] {
  return websites.filter(w => w.recentlyAdded);
}

export function getFeaturedWebsite(): Website {
  // Return daily featured based on day of year
  const featured = websites.filter(w => w.featured);
  const day = Math.floor(Date.now() / 86400000);
  return featured[day % featured.length];
}

export function getRandomWebsite(): Website {
  return websites[Math.floor(Math.random() * websites.length)];
}

export function searchWebsites(query: string): Website[] {
  const q = query.toLowerCase();
  return websites.filter(w =>
    w.title.toLowerCase().includes(q) ||
    w.description.toLowerCase().includes(q) ||
    w.tags.some(t => t.includes(q))
  );
}
